```typescript
import { loadEnv } from './util'
import { EnvSchema, type EnvConfig } from './schema'

export class ConfigValidationError extends Error {
  constructor(
    public field: string,
    public value: any,
    public reason: string
  ) {
    super(`配置验证失败: ${field} = ${value} (${reason})`)
    this.name = 'ConfigValidationError'
  }
}

export class ConfigValidator {
  private config: EnvConfig | null = null

  /**
   * 加载并验证配置
   */
  load(): EnvConfig {
    if (this.config) {
      return this.config
    }

    try {
      // 1. 加载环境变量
      const env = loadEnv()

      // 2. 验证和转换
      this.config = EnvSchema.parse(env)

      // 3. 额外验证
      this.validatePostProcessing(this.config)

      return this.config
    } catch (error: any) {
      if (error.name === 'ZodError') {
        throw new ConfigValidationError(
          'ENV',
          error.errors,
          this.formatZodError(error)
        )
      }
      throw error
    }
  }

  /**
   * 验证后处理（自定义验证逻辑）
   */
  private validatePostProcessing(config: EnvConfig): void {
    // 检查 API Token 格式
    if (!config.ANTHROPIC_AUTH_TOKEN.startsWith('sk-') && 
        !config.ANTHROPIC_AUTH_TOKEN.startsWith('Bearer ')) {
      console.warn('⚠️  API Token 格式可能不正确（应以 sk- 或 Bearer 开头）')
    }

    // 检查数据库目录
    const dbDir = require('path').dirname(config.DB_PATH)
    if (!require('fs').existsSync(dbDir)) {
      console.warn(`⚠️  数据库目录不存在: ${dbDir}，将自动创建`)
    }

    // 检查项目路径
    if (!require('fs').existsSync(config.PROJECT_PATH)) {
      throw new ConfigValidationError(
        'PROJECT_PATH',
        config.PROJECT_PATH,
        '项目路径不存在'
      )
    }
  }

  /**
   * 格式化 Zod 错误信息
   */
  private formatZodError(error: any): string {
    return error.errors.map((e: any) => {
      return `  - ${e.path.join('.')}: ${e.message}`
    }).join('\n')
  }

  /**
   * 获取配置值
   */
  get<K extends keyof EnvConfig>(key: K): EnvConfig[K] {
    if (!this.config) {
      this.load()
    }
    return this.config![key]
  }

  /**
   * 获取所有配置
   */
  getAll(): EnvConfig {
    if (!this.config) {
      this.load()
    }
    return this.config!
  }
}

// 单例
export const configValidator = new ConfigValidator()
