import { configValidator, ConfigValidationError } from './config/validator'
import { displayConfig } from './config/util'

async function main() {
  try {
    // 1. 加载并验证配置
    console.log('🔍 正在验证配置...')
    const config = configValidator.load()

    // 2. 显示配置（隐藏敏感信息）
    displayConfig(config)

    // 3. 根据配置执行相应逻辑
    if (config.AUTO_ITERATION_ENABLED) {
      const { AutoIterationEngine } = await import('./auto-iteration')

      const engine = new AutoIterationEngine({
        projectPath: config.PROJECT_PATH,
        intervalMs: config.AUTO_ITERATION_INTERVAL,
        maxIterations: config.AUTO_ITERATION_MAX_COUNT,
        autoCommit: config.AUTO_ITERATION_AUTO_COMMIT,
        autoPush: config.AUTO_ITERATION_AUTO_PUSH,
        permissionMode: config.PERMISSION_MODE,
      })

      await engine.start()
    }

    if (config.DASHBOARD_ENABLED) {
      const { startDashboard } = await import('./dashboard/server')
      await startDashboard({
        port: config.DASHBOARD_PORT,
        host: config.DASHBOARD_HOST,
      })
    }

  } catch (error: any) {
    if (error instanceof ConfigValidationError) {
      console.error('\n❌ 配置错误:')
      console.error(error.message)
      console.error('\n💡 请检查 .env 文件或环境变量')
      process.exit(1)
    }
    throw error
  }
}

main()
